async (params, browser) => {
  // Search Indeed jobs
  await browser.open('https://www.indeed.com/jobs')

  // Wait for job results
  await browser.waitForSelector('.job_seen_beacon, .jobsearch-ResultsList, #mosaic-provider-jobcards', 15000)

  // Let results render
  await browser.wait(2000)

  // Scroll to load more results
  await browser.scroll({ direction: 'down', amount: 1000 })

  await browser.wait(1500)

  // Scroll further
  await browser.scroll({ direction: 'down', amount: 1000 })

  await browser.wait(1500)

  // Extract job listings
  const search_results = await browser.evaluate(`const jobs = []; const cards = document.querySelectorAll('.job_seen_beacon, .jobsearch-SerpJobCard, div.cardOutline, .resultContent'); for (let i = 0; i < Math.min(cards.length, 15); i++) { const card = cards[i]; const titleEl = card.querySelector('h2.jobTitle a, h2.jobTitle span, a.jcs-JobTitle span'); const companyEl = card.querySelector('[data-testid="company-name"], .companyName, .company_location .companyName a, span.css-1h7lukg'); const locationEl = card.querySelector('[data-testid="text-location"], .companyLocation, .company_location .companyLocation'); const salaryEl = card.querySelector('.salary-snippet-container, .salaryOnly, div.metadata.salary-snippet-container .attribute_snippet, [data-testid="attribute_snippet_testid"]'); const snippetEl = card.querySelector('.job-snippet, .underShelfFooter, div.job-snippet ul li'); const linkEl = card.querySelector('h2.jobTitle a, a.jcs-JobTitle'); const dateEl = card.querySelector('.date, span.css-qvloho'); jobs.push({ title: titleEl ? titleEl.textContent.trim() : 'Unknown', company: companyEl ? companyEl.textContent.trim() : '', location: locationEl ? locationEl.textContent.trim() : '', salary: salaryEl ? salaryEl.textContent.trim() : 'Not listed', snippet: snippetEl ? snippetEl.textContent.trim().slice(0, 200) : '', date_posted: dateEl ? dateEl.textContent.trim() : '', url: linkEl ? 'https://www.indeed.com' + linkEl.getAttribute('href') : '' }); } return { query: '' + params.query + '', location: '' + params.location + '', job_count: jobs.length, jobs: jobs }`)

  return search_results
}
